def compute_risk_score(transaction_dict):
    score = 0.0

    if transaction_dict['amount'] > 300:
        score += 0.3
    if transaction_dict['is_international']:
        score += 0.25
    if transaction_dict['is_new_device']:
        score += 0.3
    if transaction_dict['merchant_category'] == 'crypto':
        score += 0.2
    if transaction_dict['account_age_days'] < 30:
        score += 0.25

    return min(score, 1.0)  # Cap at 1.0

def classify_from_score(risk_score, customer_tier):
    if risk_score >= 0.7:
        return 'BLOCK'
    if risk_score >= 0.4:
        if customer_tier == 'basic':
            return 'BLOCK'
        elif customer_tier == 'plus':
            return 'REVIEW'
        else:  # premium
            return 'APPROVE'
    return 'APPROVE'
